      const message = err instanceof Error ? err.message : String(err)
      results.push({
        slug: business.slug,
        name: business.name,
        type: business.type,
        sections: 0,
        meta: { title: '', description: '' },
        status: 'error',
        error: message,
      })
      console.error(`  ✗ /${business.slug} — ${business.name}: ${message}`)
    }
  }

