      <div
        className="min-h-screen"
        style={{
          fontFamily: 'var(--font-body)',
          backgroundColor: 'var(--background)',
          color: 'var(--text)',
        }}
      >
        {renderSections(page.sections)}
      </div>
      <DemoBadge isDemo={businessData.isDemo} vertical={businessData.type} />
    </>
  )
}", "exit_code": 0, "error": null}

